    /**
     * Sanitize and validate incoming filters.
     */
    private function sanitizeFilters(array $raw): array
    {
        $filters = [];

        // Date range
        if (!empty($raw['date_from']) && $this->isValidDate($raw['date_from'])) {
            $filters['date_from'] = $raw['date_from'];
        }
        if (!empty($raw['date_to']) && $this->isValidDate($raw['date_to'])) {
            $filters['date_to'] = $raw['date_to'];
        }

        // Status (single or multiple)
        if (!empty($raw['status'])) {
            if (is_array($raw['status'])) {
                $filters['status'] = array_map('trim', array_filter($raw['status']));
            } else {
                $filters['status'] = [trim($raw['status'])];
            }
        }

        // Category (single or multiple)
        if (!empty($raw['category'])) {
            if (is_array($raw['category'])) {
                $filters['category'] = array_map('trim', array_filter($raw['category']));
            } else {
                $filters['category'] = [trim($raw['category'])];
            }
        }

        // Sort
        $allowedSortColumns = ['date', 'status', 'category', 'amount', 'created_at', 'title'];
        $filters['sort_by'] = (!empty($raw['sort_by']) && in_array($raw['sort_by'], $allowedSortColumns))
            ? $raw['sort_by']
            : 'created_at';

        $filters['sort_order'] = (!empty($raw['sort_order']) && strtoupper($raw['sort_order']) === 'ASC')
            ? 'ASC'
            : 'DESC';

        // Pagination
        $filters['page'] = max(1, (int)($raw['page'] ?? 1));
        $filters['per_page'] = min(500, max(1, (int)($raw['per_page'] ?? 25)));

        // Group by
        $allowedGroupBy = ['status', 'category', 'date', 'month'];
        if (!empty($raw['group_by']) && in_array($raw['group_by'], $allowedGroupBy)) {
            $filters['group_by'] = $raw['group_by'];
        }

        // Search keyword
        if (!empty($raw['search']) && is_string($raw['search'])) {
            $filters['search'] = trim($raw['search']);
        }

        // Report type
        $allowedReportTypes = ['detail', 'summary', 'aggregated'];
        $filters['report_type'] = (!empty($raw['report_type']) && in_array($raw['report_type'], $allowedReportTypes))
            ? $raw['report_type']
            : 'detail';

        return $filters;
    }

    /**
     * Build WHERE clause and parameters from filters.
     */
    private function buildWhereClause(array $filters): array
    {
        $conditions = [];
        $params = [];

        // Date range
        if (!empty($filters['date_from'])) {
            $conditions[] = "r.created_at >= :date_from";
            $params[':date_from'] = $filters['date_from'] . ' 00:00:00';
        }
        if (!empty($filters['date_to'])) {
            $conditions[] = "r.created_at <= :date_to";
            $params[':date_to'] = $filters['date_to'] . ' 23:59:59';
        }

        // Status (IN clause with named placeholders)
        if (!empty($filters['status'])) {
            $statusPlaceholders = [];
            foreach ($filters['status'] as $i => $status) {
                $key = ":status_{$i}";
                $statusPlaceholders[] = $key;
                $params[$key] = $status;
            }
            $conditions[] = "r.status IN (" . implode(', ', $statusPlaceholders) . ")";
        }

        // Category (IN clause with named placeholders)
        if (!empty($filters['category'])) {
            $categoryPlaceholders = [];
            foreach ($filters['category'] as $i => $category) {
                $key = ":category_{$i}";
                $categoryPlaceholders[] = $key;
                $params[$key] = $category;
            }
            $conditions[] = "r.category IN (" . implode(', ', $categoryPlaceholders) . ")";
        }

        // Search keyword
        if (!empty($filters['search'])) {
            $conditions[] = "(r.title LIKE :search OR r.description LIKE :search)";
            $params[':search'] = '%' . $filters['search'] . '%';
        }

        $whereClause = '';
        if (!empty($conditions)) {
            $whereClause = 'WHERE ' . implode(' AND ', $conditions);
        }

        return [$whereClause, $params];
    }

    /**
     * Map sort_by filter value to actual column reference.
