    /**
     * Generate a detailed (row-level) report with pagination.
     */
    private function generateDetailReport(array $filters): array
    {
        [$whereClause, $params] = $this->buildWhereClause($filters);

        $sortColumn = $this->mapSortColumn($filters['sort_by']);
        $sortOrder = $filters['sort_order'];
        $offset = ($filters['page'] - 1) * $filters['per_page'];
        $limit = $filters['per_page'];

        // Count total records
        $countSql = "SELECT COUNT(*) AS total FROM reports r {$whereClause}";
        $countStmt = $this->pdo->prepare($countSql);
        $countStmt->execute($params);
        $totalRecords = (int)$countStmt->fetchColumn();

        // Fetch paginated data
        $dataSql = "
            SELECT 
                r.id,
                r.title,
                r.description,
                r.status,
                r.category,
                r.amount,
                r.created_at,
                r.updated_at
            FROM reports r
            {$whereClause}
            ORDER BY {$sortColumn} {$sortOrder}
            LIMIT :limit OFFSET :offset
        ";

        $dataStmt = $this->pdo->prepare($dataSql);
        foreach ($params as $key => $value) {
            $dataStmt->bindValue($key, $value);
        }
        $dataStmt->bindValue(':limit', $limit, PDO::PARAM_INT);
        $dataStmt->bindValue(':offset', $offset, PDO::PARAM_INT);
        $dataStmt->execute();

        $records = $dataStmt->fetchAll();

        // Quick stats for the filtered set
        $statsSql = "
            SELECT 
                COUNT(*) AS total_count,
                COALESCE(SUM(r.amount), 0) AS total_amount,
                COALESCE(AVG(r.amount), 0) AS avg_amount,
                COALESCE(MIN(r.amount), 0) AS min_amount,
                COALESCE(MAX(r.amount), 0) AS max_amount
            FROM reports r
            {$whereClause}
        ";
        $statsStmt = $this->pdo->prepare($statsSql);
        $statsStmt->execute($params);
        $stats = $statsStmt->fetch();

        return [
            'report_type'   => 'detail',
            'filters'       => $filters,
            'pagination'    => [
                'current_page'  => $filters['page'],
                'per_page'      => $filters['per_page'],
                'total_records' => $totalRecords,
                'total_pages'   => (int)ceil($totalRecords / $filters['per_page']),
            ],
            'statistics'    => $stats,
            'data'          => $records,
        ];
    }

